import { useState, forwardRef, useImperativeHandle } from "react";

const ListLessonForEdit = forwardRef((props, ref) => {
  const [root, setRoot] = useState({
      title: "Список уроков",
      collapsed: false,
      children: []
    });

    useImperativeHandle(ref, () => ({
        loadData: (data) => setRoot(data),
      }));

    const toggleRoot = () => setRoot(prev => ({ ...prev, collapsed: !prev.collapsed }));
    const toggleChild = (id) => {
    setRoot(prev => ({
      ...prev,
      children: prev.children.map(c =>
        c.id === id ? { ...c, collapsed: !c.collapsed } : c
      )
    }));
  };
  
  return (
    <div>
        {/*Header*/}
      <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
        <svg
          onClick={toggleRoot}
          style={{
            width: 20,
            height: 20,
            cursor: "pointer",
            transform: root.collapsed ? "rotate(0deg)" : "rotate(180deg)",
            transition: "0.2s"
          }}
        >
          <use href="#icon-expand" />
        </svg>
        <h2 style={{ margin: 0, flex: 1 }}>{root.title}</h2>
      </div>
      


      {!root.collapsed && (
        <div style={{ marginLeft: 25, marginTop: 10 }}>
          {root.children.map((child) => (
            <div
              key={child.id}
              style={{
                border: "1px solid #ccc",
                padding: 8,
                marginBottom: 8,
                borderRadius: 6,
                background: "#fafafa"
              }}
            >
              {/* CHILD HEADER */}
              <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                <svg
                  onClick={() => toggleChild(child.id)}
                  style={{
                    width: 18,
                    height: 18,
                    cursor: "pointer",
                    transform: child.collapsed ? "rotate(0deg)" : "rotate(180deg)",
                    transition: "0.2s"
                  }}
                >
                  <use href="#icon-expand" />
                </svg>

                <span>{child.title}</span>
              </div>

              {/* CHILD CONTENT */}
              {!child.collapsed && (
                <div style={{ marginLeft: 20, marginTop: 6 }}>
                  {child.fields.map((f) => (
                    <div
                      key={f.id}
                      style={{
                        display: "flex",
                        alignItems: "center",
                        gap: 6,
                        marginBottom: 4
                      }}
                    >
                      <span>{f.value}</span>
                    </div>
                  ))}
                </div>
              )}
            </div>
          ))}
        </div>
      )}
    </div>
  );
});

export { ListLessonForEdit }
